import { TopBar } from '@/components/dashboard/TopBar';
import { Sidebar } from '@/components/dashboard/Sidebar';
import { BalanceCard } from '@/components/dashboard/BalanceCard';
import { ExchangeRateTicker } from '@/components/dashboard/ExchangeRateTicker';
import { QuickActions } from '@/components/dashboard/QuickActions';
import { TransactionList } from '@/components/dashboard/TransactionList';
import { TransferPipelineTracker } from '@/components/dashboard/TransferPipelineTracker';
import { SendMoneyButton } from '@/components/dashboard/SendMoneyButton';
import { MOCK_BALANCES, MOCK_TRANSACTIONS, MOCK_EXCHANGE_RATE } from '@/data/mockData';
import type { User } from '@/types';

const MOCK_USER: Pick<User, 'displayName' | 'email'> = {
  displayName: 'Adaeze Okonkwo',
  email: 'adaeze@example.com',
};

const ngnBalance = MOCK_BALANCES.find((b) => b.currency === 'NGN')!;
const ghsBalance = MOCK_BALANCES.find((b) => b.currency === 'GHS')!;

const IN_PROGRESS_STATUSES = ['INITIATED', 'NAIRA_DEBITED', 'USDC_SENT', 'CEDIS_CREDITED'];
const inProgressTx = MOCK_TRANSACTIONS.find((tx) => IN_PROGRESS_STATUSES.includes(tx.status)) ?? null;

function getGreeting(): string {
  const hour = new Date().getHours();
  if (hour < 12) return 'Good morning';
  if (hour < 17) return 'Good afternoon';
  return 'Good evening';
}

export default function DashboardPage() {
  const greeting = getGreeting();
  const firstName = MOCK_USER.displayName.split(' ')[0];

  return (
    <div className="min-h-screen bg-[#080812] text-zinc-100">
      <TopBar user={MOCK_USER} />
      <div className="flex">
        <Sidebar />
        <main className="flex-1 lg:ml-52 px-4 sm:px-6 lg:px-8 py-8">
          <div className="mb-7 flex items-start justify-between gap-4">
            <div>
              <h1 className="text-xl font-semibold tracking-tight text-zinc-100">{greeting}, {firstName}</h1>
              <p className="mt-1 text-sm text-zinc-600">
                {new Date().toLocaleDateString('en-NG', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
              </p>
            </div>
            <SendMoneyButton />
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-[1fr_300px] gap-6 items-start">
            <div className="flex flex-col gap-6">
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <BalanceCard balance={ngnBalance} label="Naira balance" flag="🇳🇬" sublabel="NGN" change="₦320,000" changePositive isPrimary />
                <BalanceCard balance={ghsBalance} label="Cedis balance" flag="🇬🇭" sublabel="GHS" change="₵2,100" changePositive />
                <ExchangeRateTicker rate={MOCK_EXCHANGE_RATE.rate} fromCurrency={MOCK_EXCHANGE_RATE.from} toCurrency={MOCK_EXCHANGE_RATE.to} updatedAt={MOCK_EXCHANGE_RATE.updatedAt} />
              </div>
              <QuickActions />
              <TransactionList transactions={MOCK_TRANSACTIONS} />
            </div>

            <div className="flex flex-col gap-4">
              {inProgressTx && <TransferPipelineTracker transaction={inProgressTx} />}
              <div className="rounded-2xl border border-[#1e1e32] bg-[#0f0f1a] p-5">
                <h2 className="text-sm font-semibold text-zinc-200 mb-4">This month</h2>
                <div className="grid grid-cols-2 gap-3">
                  {[
                    { label: 'Sent', value: '₦716,800', sub: '4 transfers' },
                    { label: 'Received', value: '₦500K', sub: '1 top-up' },
                    { label: 'Avg. rate', value: '94.80', sub: 'NGN/GHS' },
                    { label: 'Saved vs bank', value: '₦12,400', sub: 'Est. fees' },
                  ].map((stat) => (
                    <div key={stat.label} className="rounded-xl bg-[#0c0c1a] border border-[#1a1a2e] p-3">
                      <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-600">{stat.label}</p>
                      <p className="mt-1.5 font-mono text-base font-semibold text-zinc-200 leading-none">{stat.value}</p>
                      <p className="mt-1 text-[10.5px] text-zinc-700">{stat.sub}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
